/* ============================================================
   白山クラブ｜ラージボール卓球  -  images.js
   ============================================================
   画像データ定義ファイル
   - IMG_1      ：クラブロゴ
   - IMG_5〜19  ：DEEP DIVE「図解スライド」全15ページ

   ※ HTMLでは <img data-img="1"> のように data-img 属性を使い、
     ページ読み込み時に該当する IMG_N を自動で src に設定します。
   ※ window.pdfPages 配列は main.js の DEEP DIVE PDFビューアで参照されます。
   ============================================================ */

'use strict';

/* ------------------------------------------------------------
   1. 画像データ（base64データURL）
   ------------------------------------------------------------ */
window.IMG_1 = 'data:image/jpeg;base64,';

window.IMG_2 = 'data:image/png;base64,';

window.IMG_5 = 'data:image/jpeg;base64,';

window.IMG_6 = 'data:image/jpeg;base64,';

window.IMG_7 = 'data:image/jpeg;base64,';

window.IMG_8 = 'data:image/jpeg;base64,';

window.IMG_9 = 'data:image/jpeg;base64,';

window.IMG_10 = 'data:image/jpeg;base64,';

window.IMG_11 = 'data:image/jpeg;base64,';

window.IMG_12 = 'data:image/jpeg;base64,';

window.IMG_13 = 'data:image/jpeg;base64,';

window.IMG_14 = 'data:image/jpeg;base64,';

window.IMG_15 = 'data:image/jpeg;base64,';

window.IMG_16 = 'data:image/jpeg;base64,';

window.IMG_17 = 'data:image/jpeg;base64,';

window.IMG_18 = 'data:image/jpeg;base64,';

window.IMG_19 = 'data:image/jpeg;base64,';


/* ------------------------------------------------------------
   2. PDFスライド用ページ配列（DEEP DIVE「図解スライド」用）
   ------------------------------------------------------------ */
window.pdfPages = [
  window.IMG_5,  window.IMG_6,  window.IMG_7,  window.IMG_8,  window.IMG_9,
  window.IMG_10, window.IMG_11, window.IMG_12, window.IMG_13, window.IMG_14,
  window.IMG_15, window.IMG_16, window.IMG_17, window.IMG_18, window.IMG_19,
];


/* ------------------------------------------------------------
   3. data-img 属性をもつ <img> へ自動適用
   ------------------------------------------------------------ */
(function applyImages() {
  function apply() {
    document.querySelectorAll('img[data-img]').forEach(function (el) {
      var n = el.getAttribute('data-img');
      var src = window['IMG_' + n];
      if (src) {
        el.src = src;
      } else {
        console.warn('[images.js] IMG_' + n + ' が未定義です');
      }
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', apply);
  } else {
    apply();
  }
})();
